import{_ as r,r as t,o,c,e as s,d as a,f as n}from"./app-c1075573.js";const _={},l=n("<p>其实最小堆是可以指定删除某个节点的，包括最大堆。只要使用正确的方法</p><p>伪代码：<br> // 向下调整<br> if (末尾节点 key &gt;  要删除的节点 key) {<br>           //这里就使用尾换头的方法调整，只不过把所谓的 &quot;头&quot; 换成了指定节点<br> }<br> // 向上调整<br> else {<br>           //这里的逻辑比尾换头简单的多，也是我们删除指定节点重要的地方，向上调整<br>           因为我们要删除的节点 key &gt;  尾节点 key，为了符合有序性的规则就必须将尾节点向上调整，调整方法也很简单：<br>          1. 把尾节点转移到我们删除的节点位置<br>          2. 循环遍历父节点，如果 key 比父节点小，那么父节点下移，当前节点上升。直到父节点   &lt; 当前节点<br>          // 注释：1. 尾节点能转移到删除节点位置就说明尾节点 key 比删除节点的所有子节点小，所以不必再调整子节点。<br>                        2. 当前节点的父节点也是删除节点的父节点，说明父节点 key &lt; 删除节点，那么当前节点上升后也不需要重新调整下                               移的原父节点<br> }</p><hr><h3>📣 觉得很赞？分享给你的朋友吧！</h3>",4);function b(m,d){const e=t("Share");return o(),c("div",null,[s(" more "),l,a(e,{services:"qq,qrcode",colorful:""})])}const p=r(_,[["render",b],["__file","11.html.vue"]]);export{p as default};
